    67→  }, [userId, mirrorId]);
    68→
    69→  // --------------- Snapshot handler (existing) ---------------
    70→
    71→  useEffect(() => {
    72→    const handleSnapshotRequest = () => {
    73→      const video = videoRef.current;
    74→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
    75→
    76→      const canvas = document.createElement("canvas");
    77→      canvas.width = video.videoWidth;
    78→      canvas.height = video.videoHeight;
    79→      const ctx = canvas.getContext("2d");
    80→      if (!ctx) return;
    81→
    82→      ctx.drawImage(video, 0, 0);
    83→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
    84→      const base64 = dataUrl.split(",")[1];
    85→
    86→      socket.emit("mirror_event", {
    87→        type: "snapshot",
    88→        image_base64: base64,
    89→        user_id: userId,
    90→      });
    91→    };
    92→
    93→    socket.on("request_snapshot", handleSnapshotRequest);
    94→    return () => {
