    96→    };
    97→  }, [videoRef, userId]);
    98→
    99→  // --------------- Mira speech streaming ---------------
   100→
   101→  useEffect(() => {
   102→    const handleMiraSpeech = (data: { text: string; is_chunk: boolean }) => {
   103→      if (data.is_chunk) {
   104→        sentenceBufferRef.current?.feed(data.text);
   105→      } else {
   106→        // End of stream — flush any remaining buffered text
   107→        sentenceBufferRef.current?.flush();
   108→      }
   109→    };
   110→
   111→    socket.on("mira_speech", handleMiraSpeech);
   112→    return () => {
   113→      socket.off("mira_speech", handleMiraSpeech);
   114→    };
   115→  }, []);
   116→
   117→  // --------------- Tool results (product carousel) ---------------
   118→
   119→  useEffect(() => {
   120→    const handleToolResult = (data: { type: string; items?: ProductCard[] }) => {
   121→      if (data.type === "clothing_results" && data.items) {
   122→        setProducts(data.items);
   123→      }
   124→    };
   125→
   126→    socket.on("tool_result", handleToolResult);
