   161→
   162→  // --------------- Session lifecycle ---------------
   163→
   164→  useEffect(() => {
   165→    const handleSessionStarted = () => {
   166→      setSessionActive(true);
   167→      avatar.startAvatar();
   168→      stt.startListening();
   169→    };
   170→
   171→    const handleSessionEnded = () => {
   172→      setSessionActive(false);
   173→      setProducts([]);
   174→      avatar.clearQueue();
   175→      avatar.stopAvatar();
   176→      stt.stopListening();
   177→    };
   178→
   179→    // The backend emits start_session acknowledgement via session's first mira_speech.
   180→    // We detect session start when we're in a room and receive the first mira_speech.
   181→    // Actually, let's listen for an explicit signal — when the client triggers start_session,
   182→    // the backend processes it. We listen for `session_active` or use start_session as our signal.
   183→    socket.on("session_active", handleSessionStarted);
   184→    socket.on("session_ended", handleSessionEnded);
   185→
   186→    return () => {
   187→      socket.off("session_active", handleSessionStarted);
   188→      socket.off("session_ended", handleSessionEnded);
   189→    };
   190→  }, [avatar.startAvatar, avatar.stopAvatar, avatar.clearQueue, stt.startListening, stt.stopListening]);
   191→
   192→  // Fallback: auto-detect session start from first mira_speech if session_active isn't emitted
   193→  const sessionStartedViaFallback = useRef(false);
   194→  useEffect(() => {
   195→    const handleFirstSpeech = () => {
   196→      if (!sessionActive && !sessionStartedViaFallback.current) {
   197→        sessionStartedViaFallback.current = true;
   198→        setSessionActive(true);
   199→        avatar.startAvatar();
   200→        stt.startListening();
   201→      }
   202→    };
   203→
   204→    socket.on("mira_speech", handleFirstSpeech);
   205→    return () => {
   206→      socket.off("mira_speech", handleFirstSpeech);
   207→      sessionStartedViaFallback.current = false;
   208→    };
   209→  }, [sessionActive, avatar.startAvatar, stt.startListening]);
   210→
   211→  // --------------- Voice transcript → backend ---------------
   212→
   213→  // When a final transcript arrives from Deepgram, either queue or send
   214→  const lastTranscriptRef = useRef("");
