   221→      pendingTranscriptsRef.current.push(stt.transcript);
   222→    } else {
   223→      // Send immediately
   224→      socket.emit("mirror_event", {
   225→        user_id: userId,
   226→        event: { type: "voice", transcript: stt.transcript },
   227→      });
   228→    }
   229→  }, [stt.transcript, avatar.isSpeaking, userId]);
   230→
   231→  // Flush pending transcripts when avatar stops speaking
   232→  useEffect(() => {
   233→    if (!avatar.isSpeaking && pendingTranscriptsRef.current.length > 0) {
