   235→      pendingTranscriptsRef.current = [];
   236→      socket.emit("mirror_event", {
   237→        user_id: userId,
   238→        event: { type: "voice", transcript: combined },
   239→      });
   240→    }
   241→  }, [avatar.isSpeaking, userId]);
   242→
   243→  // --------------- Gesture handling (dual routing) ---------------
   244→
   245→  const handleGesture = useCallback(
   246→    (gesture: DetectedGesture) => {
   247→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   248→
   249→      setLastGesture(gesture.type);
   250→      gestureKeyRef.current += 1;
   251→      setGestureKey(gestureKeyRef.current);
   252→
   253→      // Frontend: animate carousel card immediately
   254→      if (products.length > 0) {
   255→        const carouselGesture = (
   256→          window as unknown as Record<string, unknown>
   257→        ).__carouselGesture as ((g: GestureType) => void) | undefined;
   258→        carouselGesture?.(gesture.type);
   259→      }
   260→
   261→      // Backend: emit gesture event (async, Mira reacts verbally)
   262→      socket.emit("mirror_event", {
   263→        user_id: userId,
   264→        event: {
   265→          type: "gesture",
   266→          gesture: gesture.type,
   267→          confidence: gesture.confidence,
   268→        },
   269→      });
   270→    },
   271→    [userId, products.length],
   272→  );
   273→
   274→  const { isLoading: isModelLoading, error: modelError } =
   275→    useGestureRecognizer({
   276→      videoRef,
   277→      isVideoReady: isCameraReady,
   278→      onGesture: handleGesture,
   279→    });
   280→
   281→  return (
   282→    <main
   283→      style={{
   284→        position: "relative",
   285→        width: "100vw",
   286→        height: "100vh",
   287→        background: "#000",
   288→        overflow: "hidden",
   289→      }}
   290→    >
   291→      {/* Webcam feed (mirrored) */}
   292→      <video
   293→        ref={videoRef}
   294→        autoPlay
   295→        playsInline
   296→        muted
   297→        style={{
   298→          position: "absolute",
   299→          top: 0,
   300→          left: 0,
   301→          width: "100%",
   302→          height: "100%",
