   307→
   308→      {/* HeyGen Avatar PiP (top-right) */}
   309→      {sessionActive && (
   310→        <AvatarPiP videoRef={avatar.videoRef} isReady={avatar.isReady} />
   311→      )}
   312→
   313→      {/* Gesture visual feedback */}
   314→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   315→
   316→      {/* Product carousel (bottom) */}
   317→      <ProductCarousel
   318→        items={products}
   319→        onGesture={(gesture, item) => {
   320→          console.log("[Mirror] Carousel gesture:", gesture, item.title);
   321→        }}
   322→      />
   323→
   324→      {/* Voice indicator (bottom-left) */}
   325→      {sessionActive && (
   326→        <VoiceIndicator
