     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { UserProfile, clearUserData } from "@/lib/api";
     5→import GoogleSignIn from "@/components/phone/GoogleSignIn";
     6→import ProfileForm from "@/components/phone/ProfileForm";
     7→import ScrapeResults from "@/components/phone/ScrapeResults";
     8→import PokeLink from "@/components/phone/PokeLink";
     9→import QueueStatus from "@/components/phone/QueueStatus";
    10→
    11→type Step = "signin" | "profile" | "scrape" | "poke" | "queue";
    12→
    13→export default function PhonePage() {
    14→  const [step, setStep] = useState<Step>("signin");
    15→  const [user, setUser] = useState<UserProfile | null>(null);
    16→  const [error, setError] = useState("");
    17→
    18→  function handleSignIn(profile: UserProfile) {
    19→    setUser(profile);
    20→    setError("");
    21→    // If they already have a phone number, skip profile step
    22→    if (profile.phone) {
    23→      setStep("scrape");
    24→    } else {
    25→      setStep("profile");
    26→    }
    27→  }
    28→
    29→  function handleProfileComplete(updated: UserProfile) {
    30→    setUser(updated);
    31→    setError("");
    32→    setStep("scrape");
    33→  }
    34→
    35→  function handlePokeSkip() {
    36→    setStep("queue");
    37→  }
    38→
    39→  async function handleReset() {
    40→    if (!user) return;
    41→    try {
    42→      await clearUserData(user.id);
    43→      setUser(null);
    44→      setStep("signin");
    45→      setError("");
    46→    } catch (err) {
    47→      setError(err instanceof Error ? err.message : "Failed to reset");
    48→    }
    49→  }
    50→
    51→  return (
    52→    <main
    53→      style={{
    54→        minHeight: "100dvh",
    55→        display: "flex",
    56→        flexDirection: "column",
    57→        justifyContent: "center",
    58→        padding: "24px 20px",
    59→        maxWidth: 400,
    60→        margin: "0 auto",
    61→        fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
    62→      }}
    63→    >
    64→      {error && (
    65→        <div
    66→          style={{
    67→            background: "#fef2f2",
    68→            color: "#b91c1c",
    69→            padding: "12px 16px",
    70→            borderRadius: 8,
    71→            marginBottom: 20,
    72→            fontSize: 14,
    73→          }}
    74→        >
    75→          {error}
    76→        </div>
    77→      )}
    78→
    79→      {step === "signin" && (
    80→        <GoogleSignIn onSuccess={handleSignIn} onError={setError} />
    81→      )}
    82→
    83→      {step === "profile" && user && (
    84→        <ProfileForm
    85→          user={user}
    86→          onComplete={handleProfileComplete}
    87→          onError={setError}
    88→        />
    89→      )}
    90→
    91→      {step === "scrape" && user && (
    92→        <ScrapeResults userId={user.id} onContinue={() => setStep("poke")} />
    93→      )}
    94→
    95→      {step === "poke" && <PokeLink onContinue={handlePokeSkip} />}
    96→
    97→      {step === "queue" && user && <QueueStatus userId={user.id} />}
    98→
    99→      {user && (
   100→        <button
   101→          onClick={handleReset}
   102→          style={{
   103→            marginTop: 24,
   104→            padding: "8px 16px",
   105→            fontSize: 13,
   106→            color: "#999",
   107→            background: "transparent",
   108→            border: "1px solid #e5e7eb",
   109→            borderRadius: 6,
   110→            cursor: "pointer",
   111→            alignSelf: "center",
   112→          }}
   113→        >
   114→          Reset (clear data &amp; restart)
   115→        </button>
   116→      )}
   117→    </main>
   118→  );
   119→}
