   156→
   157→  const endSession = useCallback(() => {
   158→    socket.emit("end_session", { user_id: userId });
   159→    setMessages((prev) => [
   160→      ...prev,
   161→      { id: `sys-${Date.now()}`, role: "system", text: "Ending session..." },
   162→    ]);
   163→  }, [userId]);
   164→
   165→  const sendMessage = useCallback(() => {
   166→    if (!input.trim()) return;
   167→    const text = input.trim();
   168→    setInput("");
